"use client";
import { useRouter } from "next/navigation";
import { BookOpen, Target, Trophy, Mail, Phone, MapPin } from "lucide-react";

export default function Home() {
  const router = useRouter();

  return (
    <div>

      {/* HOME */}
      <section
        id="home"
        className="h-screen flex flex-col items-center justify-center bg-gradient-to-r from-blue-500 to-purple-500 text-white text-center px-6"
      >
        <h1 className="text-4xl font-bold mb-4">
          Crack Competitive Exams With Smart Practice
        </h1>

        <p className="mb-6 max-w-xl">
          Practice unlimited MCQs, track performance, and improve faster.
        </p>

        <button
          onClick={() => router.push("/register")}
          className="bg-white text-blue-600 px-6 py-2 rounded"
        >
          Start Free Now
        </button>
      </section>

      {/* ABOUT (FULL DESIGN) */}
      <section id="about" className="bg-gray-50">

        <div className="bg-gradient-to-r from-blue-600 to-purple-600 text-white py-24 px-6 text-center">
          <h1 className="text-5xl font-bold mb-6">About StudyWeb</h1>
          <p className="max-w-2xl mx-auto text-lg">
            StudyWeb is a smart online platform designed to help students prepare
            for competitive exams through unlimited practice tests, performance
            analysis, and real-time rankings.
          </p>
        </div>

        <div className="py-20 px-6 max-w-6xl mx-auto text-center">
          <h2 className="text-4xl font-bold mb-6">Our Mission</h2>
          <p className="text-gray-600 max-w-3xl mx-auto text-lg">
            Our mission is to make exam preparation smarter, faster, and more
            effective.
          </p>
        </div>

        <div className="py-20 bg-white px-6">
          <h2 className="text-4xl font-bold text-center mb-16">
            What We Offer
          </h2>

          <div className="max-w-6xl mx-auto grid md:grid-cols-3 gap-10">

            <FeatureCard icon={<BookOpen size={32} />} title="Unlimited Practice" desc="Access thousands of MCQs." />
            <FeatureCard icon={<Target size={32} />} title="Smart Analytics" desc="Track performance easily." />
            <FeatureCard icon={<Trophy size={32} />} title="Live Rankings" desc="Compete with others." />

          </div>
        </div>

      </section>

      {/* CONTACT (FULL DESIGN) */}
      <section id="contact" className="bg-gray-50 py-20 px-6">

        <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-12">

          <div>
            <h2 className="text-3xl font-bold mb-6">Get In Touch</h2>

            <div className="space-y-6 text-gray-700">
              <div className="flex gap-4"><Mail /> support@studyweb.com</div>
              <div className="flex gap-4"><Phone /> +91 98765 43210</div>
              <div className="flex gap-4"><MapPin /> India</div>
            </div>
          </div>

          <div className="bg-white shadow-lg rounded-xl p-8">
            <h3 className="text-2xl font-bold mb-6">Send a Message</h3>

            <input className="w-full mb-4 p-3 border rounded" placeholder="Name" />
            <input className="w-full mb-4 p-3 border rounded" placeholder="Email" />
            <textarea className="w-full mb-4 p-3 border rounded" placeholder="Message" />

            <button className="bg-blue-600 text-white px-6 py-2 rounded">
              Send
            </button>
          </div>

        </div>

      </section>

    </div>
  );
}

/* Components */

function FeatureCard({ icon, title, desc }: any) {
  return (
    <div className="bg-gray-100 p-8 rounded-xl text-center">
      <div className="text-blue-600 mb-4 flex justify-center">{icon}</div>
      <h3 className="font-bold">{title}</h3>
      <p className="text-gray-600">{desc}</p>
    </div>
  );
}